module synchronous_counter (
    input wire clk,
    input wire reset,
    output wire [3:0] count
);

reg [3:0] cnt_reg;

always @(posedge clk) begin
    if (reset) begin
        cnt_reg <= 4'b0;
    end else begin
        cnt_reg <= cnt_reg + 1;
    end
end

assign count = cnt_reg;

endmodule
